// 1. ดึงข้อมูลพื้นฐาน
const webhookData = $("Webhook").first().json;
const profileData = $input.first().json;
const displayName = profileData.profile?.displayName || "คุณ";
const event = webhookData?.body?.events?.[0];
const text = event?.message?.text ? event.message.text.trim() : "";

let isHandled = false;
let replyMessage = "";
let extractedData = {
    "ชื่อกิจกรรม": "",
    "วันที่": "",
    "เวลาเริ่ม": "",
    "เวลาสิ้นสุด": ""
};

// --- ฟังก์ชันแปลงเวลาภาษาไทย ---
function parseTime(s) {
    if (!s) return "";
    s = s.trim();
    let standardMatch = s.match(/([0-9]{1,2})[:.]([0-9]{2})/);
    if (standardMatch) return `${standardMatch[1].padStart(2, '0')}:${standardMatch[2]}`;

    let hour = 0;
    let minute = s.includes("ครึ่ง") ? 30 : 0;
    let numMatch = s.match(/[0-9]+/);
    let num = numMatch ? parseInt(numMatch[0]) : 0;

    if (s.includes("เที่ยงคืน")) { hour = 0; }
    else if (s.includes("เที่ยง")) { hour = 12; }
    else if (s.includes("ตี")) { hour = num || 1; }
    else if (s.includes("ทุ่ม")) { hour = (num || 1) + 18; }
    else if (s.includes("บ่าย")) { hour = (num || 1) + 12; }
    else if (s.includes("เย็น")) { hour = num <= 6 ? num + 12 : num; }
    else if (s.includes("เช้า")) { hour = num <= 6 ? num + 6 : num; }
    else if (s.includes("โมง")) {
        if (num === 0) hour = 13; 
        else if (num === 6) hour = 18;
        else if (num >= 1 && num <= 5) hour = num + 12;
        else if (num >= 7 && num <= 11) hour = num;
        else if (num === 12) hour = 12;
    } else { hour = num; }

    return `${hour.toString().padStart(2, '0')}:${minute.toString().padStart(2, '0')}`;
}

// 2. ประมวลผลข้อความ
if (event?.message?.type === "text" && text.length > 0) {

    // สกัดข้อมูลเบื้องต้น
    const subjectMatch = text.match(/(?:หัวข้อ|เรื่อง|ชื่อกิจกรรม|ชื่อ)\s*[:：]?\s*([^\n]+)/i);
    if (subjectMatch) {
        extractedData["ชื่อกิจกรรม"] = subjectMatch[1].replace(/(วันนี้|พรุ่งนี้|มะรืน|บ่าย|เช้า|เย็น|เที่ยง|ตี|ทุ่ม|โมง)\s*[\u0E00-\u0E7F0-9]+.*$/g, '').trim();
    }

    const dateMatch = text.match(/(วันนี้|พรุ่งนี้|มะรืน|[0-9]{1,2}[/-][0-9]{1,2}[/-][0-9]{2,4})/i);
    if (dateMatch) extractedData["วันที่"] = dateMatch[0].trim();

    const timeExpr = "(?:เที่ยงคืน|เที่ยง|(?:บ่าย|เช้า|เย็น|ตี)\\s*[\\u0E00-\\u0E7F0-9]+|(?:[\\u0E00-\\u0E7F0-9]+)\\s*(?:ทุ่ม|โมง(?:เช้า|เย็น)?))(?:\\s*ครึ่ง)?|[0-9]{1,2}[:.][0-9]{1,2}";
    const rangeMatch = text.match(new RegExp(`(${timeExpr})\\s*(?:ถึง|-|จนถึง)\\s*(${timeExpr})`, "i"));

    if (rangeMatch) {
        extractedData["เวลาเริ่ม"] = parseTime(rangeMatch[1]);
        extractedData["เวลาสิ้นสุด"] = parseTime(rangeMatch[2]);
    } else {
        const singleMatch = text.match(new RegExp(`(?:เวลา|ตอน|เริ่ม)\\s*[:：]?\s*(${timeExpr})`, "i")) || text.match(new RegExp(`(${timeExpr})`, "i"));
        if (singleMatch) extractedData["เวลาเริ่ม"] = parseTime(singleMatch[1]);
    }

    // 🌟 3. ตรวจสอบเวลาปัจจุบัน (บังคับ GMT+7) 🌟
    if (extractedData["วันที่"] && extractedData["เวลาเริ่ม"]) {
        // สร้างเวลาปัจจุบันแบบไทย
        const now = new Date(new Date().toLocaleString("en-US", {timeZone: "Asia/Bangkok"}));
        let checkDate = new Date(now);

        // จัดการวันที่
        if (extractedData["วันที่"].includes('พรุ่งนี้')) checkDate.setDate(now.getDate() + 1);
        else if (extractedData["วันที่"].includes('มะรืน')) checkDate.setDate(now.getDate() + 2);
        else if (!extractedData["วันที่"].includes('วันนี้')) {
            const p = extractedData["วันที่"].match(/(\d+)[/-](\d+)[/-](\d+)/);
            if (p) {
                let y = parseInt(p[3]);
                if (y > 2500) y -= 543;
                if (y < 100) y += 2000;
                checkDate = new Date(y, parseInt(p[2]) - 1, parseInt(p[1]));
            }
        }

        // ใส่เวลาเข้าไป
        const [h, m] = extractedData["เวลาเริ่ม"].split(':').map(Number);
        checkDate.setHours(h, m, 0, 0);

        // เปรียบเทียบยันนาที
        if (checkDate < now) {
            replyMessage = `คุณ ${displayName} คะ อลิซย้อนเวลาไม่ได้จริงๆ ค่ะ (ตอนนี้ ${now.getHours().toString().padStart(2,'0')}:${now.getMinutes().toString().padStart(2,'0')} น. แล้ว) รบกวนขอเป็นเวลาในอนาคตน้า 🌸`;
            isHandled = true;
        }
    }
}

return { isHandled, replyMessage, extractedData, debugText: text };

// 1. ดึงข้อมูลจากทั้ง 2 แหล่ง (Scan Input และ AI Agent)
const jsData = $("Scan Input").first().json.extractedData;
const aiOutput = $("AI Agent").first().json.output || "";

// ฟังก์ชันช่วยสกัดข้อมูลจากข้อความที่ AI ตอบกลับ (ในกรณีที่ AI ช่วยเติมข้อมูลให้)
function extractFromAI(text) {
    const summaryMatch = text.match(/📌 ชื่อกิจกรรม:\s*([^\n]+)/);
    const dateMatch = text.match(/📅 วันที่:\s*([^\n]+)/);
    const startMatch = text.match(/⏰ เวลาเริ่ม:\s*([^\n]+)/);
    const endMatch = text.match(/⏰ เวลาสิ้นสุด:\s*([^\n]+)/);

    return {
        "ชื่อกิจกรรม": summaryMatch ? summaryMatch[1].trim() : "",
        "วันที่": dateMatch ? dateMatch[1].trim() : "",
        "เวลาเริ่ม": startMatch ? startMatch[1].trim() : "",
        "เวลาสิ้นสุด": endMatch ? endMatch[1].trim() : ""
    };
}

const aiData = extractFromAI(aiOutput);

// เลือกใช้ข้อมูล: ถ้า AI มีข้อมูลให้ใช้ AI ถ้าไม่มีให้ใช้จากโหนด Scan Input
const extracted = {
    "ชื่อกิจกรรม": aiData["ชื่อกิจกรรม"] || jsData["ชื่อกิจกรรม"] || "ไม่มีชื่อกิจกรรม",
    "วันที่": aiData["วันที่"] || jsData["วันที่"] || "วันนี้",
    "เวลาเริ่ม": aiData["เวลาเริ่ม"] || jsData["เวลาเริ่ม"] || "00:00",
    "เวลาสิ้นสุด": aiData["เวลาสิ้นสุด"] || jsData["เวลาสิ้นสุด"] || ""
};

// 2. ฟังก์ชันแปลงวันที่ภาษาไทย (วันนี้, พรุ่งนี้, มะรืน หรือ วว/ดด/ปป)
function convertThaiDate(dateStr) {
    const now = new Date();
    let targetDate = new Date(now);

    if (dateStr.includes('พรุ่งนี้')) {
        targetDate.setDate(now.getDate() + 1);
    } else if (dateStr.includes('มะรืน')) {
        targetDate.setDate(now.getDate() + 2);
    } else if (!dateStr || dateStr.includes('วันนี้')) {
        // วันนี้ (ไม่ต้องเปลี่ยน)
    } else {
        const parts = dateStr.match(/(\d+)[/\\-](\d+)[/\\-](\d+)/);
        if (parts) {
            const day = parseInt(parts[1]);
            const month = parseInt(parts[2]) - 1;
            let year = parseInt(parts[3]);
            if (year > 2500) year -= 543; // แปลง พ.ศ. เป็น ค.ศ.
            targetDate = new Date(year, month, day);
        }
    }
    return targetDate;
}

// 3. ฟังก์ชันรวมวันที่กับเวลา (HH:mm)
function combineDateTime(dateObj, timeStr) {
    const [hour, minute] = timeStr.split(':').map(Number);
    const dt = new Date(dateObj);
    dt.setHours(hour || 0, minute || 0, 0, 0);
    return dt;
}

// 🌟 4. ฟังก์ชันสำคัญ: แปลงเวลาเป็น ISO แบบ Local 
function toLocalISOString(date) {
    const pad = (num) => (num < 10 ? '0' : '') + num;
    return date.getFullYear() +
        '-' + pad(date.getMonth() + 1) +
        '-' + pad(date.getDate()) +
        'T' + pad(date.getHours()) +
        ':' + pad(date.getMinutes()) +
        ':' + pad(date.getSeconds());
}

// --- เริ่มประมวลผล ---
const eventDate = convertThaiDate(extracted["วันที่"]);
const startDateTime = combineDateTime(eventDate, extracted["เวลาเริ่ม"]);

let endDateTime;
if (extracted["เวลาสิ้นสุด"] && extracted["เวลาสิ้นสุด"] !== "") {
    endDateTime = combineDateTime(eventDate, extracted["เวลาสิ้นสุด"]);
} else {
    // ถ้าไม่มีเวลาสิ้นสุด ให้ตั้งเป็น 1 ชั่วโมงหลังจากเวลาเริ่ม
    endDateTime = new Date(startDateTime.getTime() + 60 * 60 * 1000);
}

// ป้องกันกรณีเวลาจบ น้อยกว่าเวลาเริ่ม
if (endDateTime <= startDateTime) {
    endDateTime = new Date(startDateTime.getTime() + 60 * 60 * 1000);
}

return {
    summary: extracted["ชื่อกิจกรรม"],
    startISO: toLocalISOString(startDateTime),
    endISO: toLocalISOString(endDateTime)
};
